data class User(val id: Long, val name: String, val email: String)

val u1 = User(1, "Alice", "alice@x.com")
val u2 = u1.copy(email = "a@x.com")            // new instance, only email changed
println(u1 == u2)                                // false — emails differ
println(u1.hashCode() == User(1, "Alice", "alice@x.com").hashCode()) // true

// Destructuring
val (id, name, email) = u1
println("$id $name $email")

// In Maps / Sets — Identity by content
val seen = mutableSetOf(u1)
println(seen.contains(User(1, "Alice", "alice@x.com"))) // true

// Pitfall: equality is structural, not deep — beware mutable List members.
// Pitfall: copy() does a SHALLOW copy of properties — nested mutable objects shared.

// Common usage: UI state
sealed interface FeedState {
  data object Loading : FeedState
  data class Success(val posts: List<Post>) : FeedState
  data class Error(val message: String) : FeedState
}

// Pattern match via when
fun render(state: FeedState) = when (state) {
  is FeedState.Loading -> "..."
  is FeedState.Success -> "\${state.posts.size} posts"
  is FeedState.Error   -> state.message
}

sealed interface ApiResult<out T> {
  data class Success<T>(val value: T) : ApiResult<T>
  data class Failure(val code: Int, val message: String) : ApiResult<Nothing>
  data object Loading : ApiResult<Nothing>
}

fun <T> handle(r: ApiResult<T>) = when (r) {
  is ApiResult.Success -> println("got \${r.value}")
  is ApiResult.Failure -> println("err \${r.code}")
  ApiResult.Loading    -> println("loading")
  // No else — exhaustive
}

// AST modelling
sealed class Expr
class Num(val value: Double) : Expr()
class Add(val left: Expr, val right: Expr) : Expr()
class Mul(val left: Expr, val right: Expr) : Expr()

fun eval(e: Expr): Double = when (e) {
  is Num -> e.value
  is Add -> eval(e.left) + eval(e.right)
  is Mul -> eval(e.left) * eval(e.right)
}

// Adding an extension subclass after the fact — forces every `when` to update
class Sub(val left: Expr, val right: Expr) : Expr() // compiler errors at every when

// object — singleton
object Logger {
  fun log(msg: String) = println("[LOG] \$msg")
}
Logger.log("hello")

// Anonymous object — implement an interface inline
val listener = object : ClickListener {
  override fun onClick() = println("click")
}

// companion object — static-like factory
class User private constructor(val id: Long, val name: String) {
  companion object {
    const val MIN_NAME_LEN = 2
    fun create(name: String): User? =
      if (name.length >= MIN_NAME_LEN) User(System.currentTimeMillis(), name) else null
  }
}
val u = User.create("Alice")
User.MIN_NAME_LEN          // accessed like static

// Named companion object
class Cache { companion object Shared { fun get() = TODO() } }
Cache.get()                // shorthand
Cache.Shared.get()          // also works

// Common pattern: sealed + companion factories
sealed interface Currency {
  data class USD(val amount: Long) : Currency
  data class EUR(val amount: Long) : Currency
  companion object {
    fun parse(s: String): Currency? = when (s.takeLast(3)) {
      "USD" -> USD(s.dropLast(3).trim().toLong())
      "EUR" -> EUR(s.dropLast(3).trim().toLong())
      else  -> null
    }
  }
}

fun String.titleCase(): String =
  split(" ").joinToString(" ") { it.replaceFirstChar(Char::uppercase) }

println("hello world".titleCase()) // Hello World

// Extension property — no backing field, computed
val <T> List<T>.middle: T?
  get() = if (isEmpty()) null else this[size / 2]

println(listOf(1, 2, 3, 4, 5).middle) // 3

// Nullable receiver — handle null inside
fun String?.orEmpty(): String = this ?: ""
val s: String? = null
println(s.orEmpty()) // ""

// Static dispatch — important to know
open class A
class B : A()
fun A.name() = "A"
fun B.name() = "B"

fun whoCalls(a: A) = a.name()  // always returns "A" — static type wins

// Member wins over extension with same signature
class Animal { fun sound() = "member" }
fun Animal.sound() = "extension"
println(Animal().sound()) // "member"

// Scope a helper to where it's used (top-level inside a feature module is fine)

// let — null-safe transform
val len: Int? = name?.let { it.length }

// also — side effect in a chain
val token = login()
  .also { logger.debug("login result: \$it") }
  .takeIf { it.isNotEmpty() }

// apply — fluent configuration
val intent = Intent(this, DetailActivity::class.java).apply {
  putExtra("id", id)
  flags = Intent.FLAG_ACTIVITY_NEW_TASK
}

// run — execute on receiver, return value
val description = user.run {
  "\$name (\$email)"
}

// with — same shape, free function
val result = with(StringBuilder()) {
  append("Hello, ")
  append(name)
  toString()
}

// Decision matrix
// Need to refer to receiver as `it`?       → let / also
// Need to refer to receiver as `this`?     → run / apply / with
// Want lambda's result?                     → let / run / with
// Want the receiver back?                   → apply / also

// Anti-pattern: deeply nested scope functions hide control flow
// Refactor to a named function when the chain gets > 2 deep.

// open — opt in to inheritance
open class Repository(open val baseUrl: String) {
  open fun fetch(): String = "data"
  fun health() = "ok"            // final by default — not overridable
}

class UserRepository(baseUrl: String) : Repository(baseUrl) {
  override fun fetch() = "users"
}

// abstract — can't instantiate, can hold state
abstract class Animal(val name: String) {
  abstract fun sound(): String
  fun greet() = "Hi, I'm \$name"
}
class Dog(name: String) : Animal(name) {
  override fun sound() = "Woof"
}

// interface — multiple inheritance, default impl
interface Logger {
  fun log(msg: String)
  fun debug(msg: String) = log("[DEBUG] \$msg")  // default impl
}
interface Cacheable {
  fun cacheKey(): String
}
class Service : Logger, Cacheable {
  override fun log(msg: String) = println(msg)
  override fun cacheKey() = "svc:1"
}

// Diamond — when two interfaces have same default, override required
interface A { fun greet() = "A" }
interface B { fun greet() = "B" }
class C : A, B {
  override fun greet() = super<A>.greet() + super<B>.greet()
}
